import{_ as s,o as i,c as n,a0 as t}from"./chunks/framework.Bogozrur.js";const k=JSON.parse('{"title":"LangGraph","description":"","frontmatter":{},"headers":[],"relativePath":"notes/langgraph.md","filePath":"notes/langgraph.md","lastUpdated":null}'),l={name:"notes/langgraph.md"};function e(h,a,r,p,o,g){return i(),n("div",null,[...a[0]||(a[0]=[t(`<h1 id="langgraph" tabindex="-1">LangGraph <a class="header-anchor" href="#langgraph" aria-label="Permalink to &quot;LangGraph&quot;">​</a></h1><h2 id="是什么" tabindex="-1">是什么？ <a class="header-anchor" href="#是什么" aria-label="Permalink to &quot;是什么？&quot;">​</a></h2><p>LangGraph 是一个用于构建有状态的、多参与者 LLM 应用的框架。它在 LangChain 的基础上引入了基于图的编程模型——节点代表计算步骤，边定义执行流程。这使它非常适合构建复杂的 Agent 工作流。</p><h2 id="解决什么问题" tabindex="-1">解决什么问题？ <a class="header-anchor" href="#解决什么问题" aria-label="Permalink to &quot;解决什么问题？&quot;">​</a></h2><p>用简单的 chain-of-thought 提示来构建生产级 Agent 系统有几个局限性：</p><ul><li><strong>状态管理</strong> — 跨步骤跟踪对话状态、中间结果和上下文容易出错</li><li><strong>循环工作流</strong> — Agent 通常需要循环、重试或根据条件分支；线性链无法表达这些</li><li><strong>人在回路</strong> — 生产系统需要检查点来支持人工审核和批准</li><li><strong>可观测性</strong> — 调试多步 Agent 工作流需要对每一步有清晰的可见性</li></ul><p>LangGraph 通过其基于图的架构解决了所有这些问题。</p><h2 id="核心流程" tabindex="-1">核心流程 <a class="header-anchor" href="#核心流程" aria-label="Permalink to &quot;核心流程&quot;">​</a></h2><p>一个 LangGraph 应用被定义为一个状态图：</p><ol><li><strong>定义状态</strong> — 创建一个类型化的状态 schema，在图中流转</li><li><strong>创建节点</strong> — 每个节点是一个读取和更新状态的函数</li><li><strong>定义边</strong> — 用条件边或无条件边连接节点</li><li><strong>编译</strong> — 将图构建为可执行的应用</li><li><strong>运行</strong> — 用初始状态调用图</li></ol><div class="language-python vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">python</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">from</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> langgraph.graph </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">import</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> StateGraph</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">graph </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> StateGraph(AgentState)</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">graph.add_node(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;agent&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, agent_node)</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">graph.add_node(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;tools&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, tool_node)</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">graph.add_edge(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;agent&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;should_continue&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">graph.add_conditional_edges(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;should_continue&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, router)</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">app </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> graph.compile()</span></span></code></pre></div><h2 id="核心概念" tabindex="-1">核心概念 <a class="header-anchor" href="#核心概念" aria-label="Permalink to &quot;核心概念&quot;">​</a></h2><p><strong>状态（State）：</strong> 在图中流转的核心数据结构。每个节点接收当前状态并返回更新。状态通常是 <code>TypedDict</code> 或 Pydantic 模型。</p><p><strong>节点（Nodes）：</strong> 执行计算的函数。每个节点接收状态、处理它，并返回部分状态更新。节点可以调用 LLM、调用工具或执行任意逻辑。</p><p><strong>边（Edges）：</strong> 节点之间的连接。可以是无条件的（总是从 A 到 B）或有条件的（根据状态值路由）。</p><p><strong>循环（Cycles）：</strong> 与 DAG 不同，LangGraph 支持循环。这对于 Agent 循环至关重要——Agent 需要反复推理、行动和观察，直到任务完成。</p><p><strong>检查点（Checkpoints）：</strong> 内置的持久化机制，在每一步保存图的状态。支持时间旅行调试、人在回路工作流和容错。</p><p><strong>子图（Subgraphs）：</strong> 图可以嵌套在其他图中，支持模块化设计和通用工作流的复用。</p><h2 id="后续探索方向" tabindex="-1">后续探索方向 <a class="header-anchor" href="#后续探索方向" aria-label="Permalink to &quot;后续探索方向&quot;">​</a></h2><ul><li>使用 interrupt 和 resume 的人在回路模式</li><li>图执行的流式输出</li><li>LangGraph Platform 部署与监控</li><li>将 LangGraph 与 RAG 流水线结合</li><li>使用 supervisor 模式构建多智能体系统</li></ul>`,20)])])}const E=s(l,[["render",e]]);export{k as __pageData,E as default};
